package Lec6;

public class Using_For_Loop {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

// print "hello" five times using For loop

// Syntax of For loop (Always we don't use semicolon after i++ if we using all i related things together
//Also we can do inccreement of i inside the loop too while using For loop

// Step1: intialization of i
// Step2: condition will perform
//Step3: Work inside the loop will perform
//Step4: i increement will done

int N=5;
for(int i=1; i<=N; i++) //here first we intialized the i by 1 then condition will check then work will peroform which is inside the loop then i increement will done
{
System.out.println("Hello");
//i++; : inside the for loop also we do while using For loop
}
	}

}
